import { cacheTag } from 'next/cache';

export type Post = {
  id: number;
  title: string;
  content: string;
  createdAt: Date;
};

// In-memory store (a real app would use a database)
let nextId = 1;
const posts: Post[] = [];

export async function getPosts(): Promise<Post[]> {
  'use cache';
  cacheTag('posts');

  // Simulate a database query delay
  await new Promise((resolve) => setTimeout(resolve, 500));

  return posts
    .slice()
    .reverse()
    .map((post) => ({ ...post }));
}

export function createPostInDb(title: string, content: string): Post {
  const post: Post = {
    id: nextId++,
    title,
    content,
    createdAt: new Date(),
  };
  posts.push(post);
  return post;
}

'use server';

import { updateTag } from 'next/cache';
import { createPostInDb } from '@/lib/posts';

export type CreatePostState = {
  success: boolean;
  error?: string;
};

export async function createPost(
  prevState: CreatePostState,
  formData: FormData,
): Promise<CreatePostState> {
  const title = formData.get('title')?.toString().trim();
  const content = formData.get('content')?.toString().trim();

  if (!title) {
    return { success: false, error: 'Title is required.' };
  }

  if (!content) {
    return { success: false, error: 'Content is required.' };
  }

  // Simulate a database write delay
  await new Promise((resolve) => setTimeout(resolve, 300));

  createPostInDb(title, content);

  // Immediately expire all cached data tagged with 'posts'.
  // updateTag guarantees that the next request to read posts will
  // wait for fresh data — no stale-while-revalidate, no stale content.
  updateTag('posts');

  return { success: true };
}

import { getPosts } from '@/lib/posts';
import { PostForm } from './post-form';

export default async function Home() {
  const posts = await getPosts();

  return (
    <main style={{ maxWidth: 640, margin: '0 auto', padding: '2rem 1rem' }}>
      <h1>Posts</h1>

      <PostForm />

      <h2>All Posts</h2>
      {posts.length === 0 ? (
        <p>No posts yet. Create one above!</p>
      ) : (
        <ul style={{ listStyle: 'none', padding: 0 }}>
          {posts.map((post) => (
            <li
              key={post.id}
              style={{
                border: '1px solid #ddd',
                borderRadius: 8,
                padding: '1rem',
                marginBottom: '0.75rem',
              }}
            >
              <h3 style={{ margin: '0 0 0.25rem' }}>{post.title}</h3>
              <p style={{ margin: 0, color: '#555' }}>{post.content}</p>
              <small style={{ color: '#999' }}>
                {post.createdAt.toLocaleString()}
              </small>
            </li>
          ))}
        </ul>
      )}
    </main>
  );
}

'use client';

import { useActionState } from 'react';
import { createPost, type CreatePostState } from './actions';

const initialState: CreatePostState = { success: false };

export function PostForm() {
  const [state, formAction, pending] = useActionState(
    createPost,
    initialState,
  );

  return (
    <form action={formAction} style={{ marginBottom: '2rem' }}>
      <div style={{ marginBottom: '0.75rem' }}>
        <label htmlFor="title" style={{ display: 'block', marginBottom: 4 }}>
          Title
        </label>
        <input
          id="title"
          name="title"
          type="text"
          disabled={pending}
          required
          style={{ width: '100%', padding: '0.5rem' }}
        />
      </div>

      <div style={{ marginBottom: '0.75rem' }}>
        <label htmlFor="content" style={{ display: 'block', marginBottom: 4 }}>
          Content
        </label>
        <textarea
          id="content"
          name="content"
          rows={4}
          disabled={pending}
          required
          style={{ width: '100%', padding: '0.5rem' }}
        />
      </div>

      <button type="submit" disabled={pending}>
        {pending ? 'Creating…' : 'Create Post'}
      </button>

      {state.success && (
        <p style={{ color: 'green', marginTop: '0.5rem' }}>
          Post created! Refreshing posts…
        </p>
      )}

      {state.error && (
        <p style={{ color: 'red', marginTop: '0.5rem' }}>{state.error}</p>
      )}
    </form>
  );
}

